ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
    success: true,
    data: {
        paymentId: vars.paymentId,
        orderId: vars.paymentRequest.orderId,
        status: "CAPTURED",
        authorizationCode: vars.authorizationResponse.authorizationCode,
        captureId: vars.captureResponse.captureId default "",
        amount: vars.paymentRequest.amount,
        currency: vars.paymentRequest.currency default "USD",
        paymentMethod: vars.paymentRequest.paymentMethod default "CREDIT_CARD",
        processedAt: now() as String {format: "yyyy-MM-dd'T'HH:mm:ss.SSSZ"}
    },
    correlationId: correlationId,
    timestamp: now() as String {format: "yyyy-MM-dd'T'HH:mm:ss.SSSZ"}
}

%dw 2.0
output application/json
---
{
    success: false,
    data: {
        paymentId: vars.paymentId,
        orderId: vars.paymentRequest.orderId,
        status: "DECLINED",
        declineReason: vars.authorizationResponse.declineReason default "Payment was declined by the payment processor",
        declineCode: vars.authorizationResponse.declineCode default "UNKNOWN"
    },
    correlationId: correlationId,
    timestamp: now() as String {format: "yyyy-MM-dd'T'HH:mm:ss.SSSZ"}
}
